/*ReportWrite0A0.selectReport0A0ExcelList*/ SELECT T.DGRCOMPO_ID AS DGRCOMPO_ID , T.UP_DGRCOMPO_ID AS UP_DGRCOMPO_ID , CAST(T.DGR_LEVEL AS NUMERIC(5, 0)) AS DGR_LEVEL , T.REPORT_DETL_CD AS REPORT_DETL_CD , TRIM(CASE WHEN T.DGR_LEVEL = 0 THEN T.OFFICE_NM WHEN T.DGR_LEVEL = 1 THEN T.COMP_GROUND WHEN T.DGR_LEVEL > 1 THEN LAVEL_SYMBOL || T.COMP_GROUND ELSE '' END) AS DGRCOMPO_NM , CAST((T.FRSC_AMT1/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS FRSC_AMT1 , CAST((T.FRSC_AMT2/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS FRSC_AMT2 , CAST((T.FRSC_AMT3/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS FRSC_AMT3 , CAST((T.FRSC_AMT4/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS FRSC_AMT4 , CAST((T.FRSC_AMT5/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS FRSC_AMT5 , CAST((T.FRSC_AMT6/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS FRSC_AMT6 , CAST((T.DMN_FRSC_AMT1/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS DMN_FRSC_AMT1 , CAST((T.DMN_FRSC_AMT2/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS DMN_FRSC_AMT2 , CAST((T.DMN_FRSC_AMT3/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS DMN_FRSC_AMT3 , CAST((T.DMN_FRSC_AMT4/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS DMN_FRSC_AMT4 , CAST((T.DMN_FRSC_AMT5/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS DMN_FRSC_AMT5 , CAST((T.DMN_FRSC_AMT6/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS DMN_FRSC_AMT6 , CAST((T.PRE_FRSC_AMT1/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS PRE_FRSC_AMT1 , CAST((T.PRE_FRSC_AMT2/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS PRE_FRSC_AMT2 , CAST((T.PRE_FRSC_AMT3/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS PRE_FRSC_AMT3 , CAST((T.PRE_FRSC_AMT4/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS PRE_FRSC_AMT4 , CAST((T.PRE_FRSC_AMT5/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS PRE_FRSC_AMT5 , CAST((T.PRE_FRSC_AMT6/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS PRE_FRSC_AMT6 , CAST((T.PRE_DEF_FRSC_AMT1/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS PRE_DEF_FRSC_AMT1 , CAST((T.PRE_DEF_FRSC_AMT2/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS PRE_DEF_FRSC_AMT2 , CAST((T.PRE_DEF_FRSC_AMT3/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS PRE_DEF_FRSC_AMT3 , CAST((T.PRE_DEF_FRSC_AMT4/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS PRE_DEF_FRSC_AMT4 , CAST((T.PRE_DEF_FRSC_AMT5/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS PRE_DEF_FRSC_AMT5 , CAST((T.PRE_DEF_FRSC_AMT6/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS PRE_DEF_FRSC_AMT6 , T.COMPO_LEVEL AS COMPO_LEVEL , T.REFLECT_FG AS REFLECT_FG , T.DEMAND_CONT AS DEMAND_CONT , T.EXAM_CONT AS EXAM_CONT , T.MAYOR_REPORT_YN AS MAYOR_REPORT_YN , T.REFLECT_FG_NM AS REFLECT_FG_NM , DECODE(T.TE_MNG_MOK_CD, NULL, '', '', '', '00000', '', SUBSTR(T.TE_MNG_MOK_CD, 1, 3) || '-' || SUBSTR(T.TE_MNG_MOK_CD, 4)) || ' ' AS TE_MNG_MOK_CD FROM (SELECT A.DGRCOMPO_ID AS DGRCOMPO_ID , A.UP_DGRCOMPO_ID AS UP_DGRCOMPO_ID , A.DGR_LEVEL AS DGR_LEVEL , A.FIS_YEAR AS FIS_YEAR , A.BGT_DGR AS BGT_DGR , A.TE_BGT_COMPO_ID AS TE_BGT_COMPO_ID , A.REPORT_CD AS REPORT_CD , A.REPORT_DETL_CD AS REPORT_DETL_CD , A.OFFICE_CD AS OFFICE_CD , A.DEPT_CD AS DEPT_CD , A.DBIZ_CD AS DBIZ_CD , A.TE_MNG_MOK_CD AS TE_MNG_MOK_CD , A.TE_BGT_COMPO_SEQ AS TE_BGT_COMPO_SEQ , A.COMPO_LEVEL AS COMPO_LEVEL , A.COMP_GROUND AS COMP_GROUND , A.SORT_SEQ AS SORT_SEQ , A.REFLECT_FG AS REFLECT_FG , A.DEMAND_CONT AS DEMAND_CONT , A.EXAM_CONT AS EXAM_CONT , A.FRSC_AMT1 AS FRSC_AMT1 , A.FRSC_AMT2 AS FRSC_AMT2 , A.FRSC_AMT3 AS FRSC_AMT3 , A.FRSC_AMT4 AS FRSC_AMT4 , A.FRSC_AMT5 AS FRSC_AMT5 , A.FRSC_AMT6 AS FRSC_AMT6 , A.DMN_FRSC_AMT1 AS DMN_FRSC_AMT1 , A.DMN_FRSC_AMT2 AS DMN_FRSC_AMT2 , A.DMN_FRSC_AMT3 AS DMN_FRSC_AMT3 , A.DMN_FRSC_AMT4 AS DMN_FRSC_AMT4 , A.DMN_FRSC_AMT5 AS DMN_FRSC_AMT5 , A.DMN_FRSC_AMT6 AS DMN_FRSC_AMT6 , A.PRE_FRSC_AMT1 AS PRE_FRSC_AMT1 , A.PRE_FRSC_AMT2 AS PRE_FRSC_AMT2 , A.PRE_FRSC_AMT3 AS PRE_FRSC_AMT3 , A.PRE_FRSC_AMT4 AS PRE_FRSC_AMT4 , A.PRE_FRSC_AMT5 AS PRE_FRSC_AMT5 , A.PRE_FRSC_AMT6 AS PRE_FRSC_AMT6 , A.PRE_DEF_FRSC_AMT1 AS PRE_DEF_FRSC_AMT1 , A.PRE_DEF_FRSC_AMT2 AS PRE_DEF_FRSC_AMT2 , A.PRE_DEF_FRSC_AMT3 AS PRE_DEF_FRSC_AMT3 , A.PRE_DEF_FRSC_AMT4 AS PRE_DEF_FRSC_AMT4 , A.PRE_DEF_FRSC_AMT5 AS PRE_DEF_FRSC_AMT5 , A.PRE_DEF_FRSC_AMT6 AS PRE_DEF_FRSC_AMT6 , A.MAYOR_REPORT_YN AS MAYOR_REPORT_YN , NVL((SELECT Z.DETL_CD_NM FROM TB_COMMCDDETL Z WHERE Z.CL_CD = 'RP002' AND Z.DETL_CD = A.REPORT_DETL_CD AND ROWNUM = 1), '') AS REPORT_DETL_NM , NVL((SELECT Z.DETL_CD_NM FROM TB_COMMCDDETL Z WHERE Z.CL_CD = 'RP003' AND Z.DETL_CD = A.REFLECT_FG AND ROWNUM = 1), '') AS REFLECT_FG_NM , NVL((SELECT Z.OFFICE_RANK FROM TB_DGRDEPT Z WHERE Z.FIS_YEAR = A.FIS_YEAR AND Z.BGT_DGR = A.BGT_DGR AND Z.OFFICE_CD = A.OFFICE_CD AND ROWNUM = 1), 0) AS OFFICE_RANK , NVL((SELECT Z.OFFICE_NM FROM TB_DGRDEPT Z WHERE Z.FIS_YEAR = A.FIS_YEAR AND Z.BGT_DGR = A.BGT_DGR AND Z.OFFICE_CD = A.OFFICE_CD AND ROWNUM = 1), 0) AS OFFICE_NM , NVL((SELECT Z.DEPT_RANK FROM TB_DGRDEPT Z WHERE Z.FIS_YEAR = A.FIS_YEAR AND Z.BGT_DGR = A.BGT_DGR AND Z.DEPT_CD = A.DEPT_CD AND ROWNUM = 1), 0) AS DEPT_RANK , NVL((SELECT Z.DEPT_NM FROM TB_DGRDEPT Z WHERE Z.FIS_YEAR = A.FIS_YEAR AND Z.BGT_DGR = A.BGT_DGR AND Z.DEPT_CD = A.DEPT_CD AND ROWNUM = 1), '') AS DEPT_NM , NVL((SELECT Z.PBIZ_RANK FROM TB_DGRBIZ Z WHERE Z.FIS_YEAR = A.FIS_YEAR AND Z.BGT_DGR = A.BGT_DGR AND Z.DBIZ_CD = A.DBIZ_CD AND ROWNUM = 1), 0) AS PBIZ_RANK , NVL((SELECT Z.PBIZ_CD FROM TB_DGRBIZ Z WHERE Z.FIS_YEAR = A.FIS_YEAR AND Z.BGT_DGR = A.BGT_DGR AND Z.DBIZ_CD = A.DBIZ_CD AND ROWNUM = 1), 0) AS PBIZ_CD , NVL((SELECT Z.UBIZ_RANK FROM TB_DGRBIZ Z WHERE Z.FIS_YEAR = A.FIS_YEAR AND Z.BGT_DGR = A.BGT_DGR AND Z.DBIZ_CD = A.DBIZ_CD AND ROWNUM = 1), 0) AS UBIZ_RANK , NVL((SELECT Z.UBIZ_CD FROM TB_DGRBIZ Z WHERE Z.FIS_YEAR = A.FIS_YEAR AND Z.BGT_DGR = A.BGT_DGR AND Z.DBIZ_CD = A.DBIZ_CD AND ROWNUM = 1), 0) AS UBIZ_CD , NVL((SELECT Z.DBIZ_RANK FROM TB_DGRBIZ Z WHERE Z.FIS_YEAR = A.FIS_YEAR AND Z.BGT_DGR = A.BGT_DGR AND Z.DBIZ_CD = A.DBIZ_CD AND ROWNUM = 1), 0) AS DBIZ_RANK , NVL((SELECT Z.DBIZ_NM FROM TB_DGRBIZ Z WHERE Z.FIS_YEAR = A.FIS_YEAR AND Z.BGT_DGR = A.BGT_DGR AND Z.DBIZ_CD = A.DBIZ_CD AND ROWNUM = 1), '') AS DBIZ_NM , NVL((SELECT COUNT(*) FROM TB_DGRCOMPO Z WHERE Z.FIS_YEAR = A.FIS_YEAR AND Z.BGT_DGR = A.BGT_DGR AND Z.UP_TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID), 0) AS CHILD_CNT , NVL((SELECT Z.SYMBOL FROM TB_DGRCOMPOSYMBOL Z WHERE Z.FIS_YEAR = A.FIS_YEAR AND Z.BGT_DGR = A.BGT_DGR AND Z.COMPO_LEVEL = A.COMPO_LEVEL AND SYMBOL_LENGTH > 0), '') AS LAVEL_SYMBOL FROM ( SELECT T.* FROM (SELECT DECODE(H.CT, 1, A.FIS_YEAR || '_' || TO_CHAR(A.BGT_DGR, '000') || '_' || A.REPORT_DETL_CD || '_' || A.OFFICE_CD || '_' '00000000000' , 2, A.FIS_YEAR || '_' || TO_CHAR(A.BGT_DGR, '000') || '_' || A.REPORT_DETL_CD || '_' || A.OFFICE_CD || '_' || A.TE_BGT_COMPO_ID) AS DGRCOMPO_ID , DECODE(H.CT, 1, A.FIS_YEAR || '_' || TO_CHAR(A.BGT_DGR, '000') || '_' || A.REPORT_DETL_CD || '_' || '0000' || '_' || '00000000000' , 2, A.FIS_YEAR || '_' || TO_CHAR(A.BGT_DGR, '000') || '_' || A.REPORT_DETL_CD || '_' || A.OFFICE_CD || '_' || A.UP_TE_BGT_COMPO_ID) AS UP_DGRCOMPO_ID , DECODE(H.CT, 1, 0, A.COMPO_LEVEL) AS DGR_LEVEL , A.FIS_YEAR AS FIS_YEAR , A.BGT_DGR AS BGT_DGR , A.REPORT_CD AS REPORT_CD , A.REPORT_DETL_CD AS REPORT_DETL_CD , DECODE(H.CT, 1, '00000000000', A.TE_BGT_COMPO_ID) AS TE_BGT_COMPO_ID , A.OFFICE_CD AS OFFICE_CD , DECODE(H.CT, 1, '0000000', A.DEPT_CD) AS DEPT_CD , DECODE(H.CT, 1, '0000000000000000', A.DBIZ_CD) AS DBIZ_CD , DECODE(H.CT, 1, '00000', A.TE_MNG_MOK_CD) AS TE_MNG_MOK_CD , DECODE(H.CT, 1, 0, A.TE_BGT_COMPO_SEQ) AS TE_BGT_COMPO_SEQ , DECODE(H.CT, 1, 0, A.COMPO_LEVEL) AS COMPO_LEVEL , DECODE(H.CT, 1, '', A.COMP_GROUND) AS COMP_GROUND , DECODE(H.CT, 1, 0, A.SORT_SEQ) AS SORT_SEQ , DECODE(H.CT, 1, '', A.REFLECT_FG) AS REFLECT_FG , DECODE(H.CT, 1, '', A.DEMAND_CONT) AS DEMAND_CONT , DECODE(H.CT, 1, '', A.EXAM_CONT) AS EXAM_CONT , DECODE(H.CT, 1, '', A.MAYOR_REPORT_YN) AS MAYOR_REPORT_YN , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.FRSC_AMT1, 0), A.FRSC_AMT1)) AS FRSC_AMT1 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.FRSC_AMT2, 0), A.FRSC_AMT2)) AS FRSC_AMT2 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.FRSC_AMT3, 0), A.FRSC_AMT3)) AS FRSC_AMT3 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.FRSC_AMT4, 0), A.FRSC_AMT4)) AS FRSC_AMT4 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.FRSC_AMT5, 0), A.FRSC_AMT5)) AS FRSC_AMT5 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.FRSC_AMT6, 0), A.FRSC_AMT6)) AS FRSC_AMT6 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.DMN_FRSC_AMT1, 0), A.DMN_FRSC_AMT1)) AS DMN_FRSC_AMT1 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.DMN_FRSC_AMT2, 0), A.DMN_FRSC_AMT2)) AS DMN_FRSC_AMT2 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.DMN_FRSC_AMT3, 0), A.DMN_FRSC_AMT3)) AS DMN_FRSC_AMT3 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.DMN_FRSC_AMT4, 0), A.DMN_FRSC_AMT4)) AS DMN_FRSC_AMT4 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.DMN_FRSC_AMT5, 0), A.DMN_FRSC_AMT5)) AS DMN_FRSC_AMT5 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.DMN_FRSC_AMT6, 0), A.DMN_FRSC_AMT6)) AS DMN_FRSC_AMT6 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_FRSC_AMT1, 0), A.PRE_FRSC_AMT1)) AS PRE_FRSC_AMT1 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_FRSC_AMT2, 0), A.PRE_FRSC_AMT2)) AS PRE_FRSC_AMT2 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_FRSC_AMT3, 0), A.PRE_FRSC_AMT3)) AS PRE_FRSC_AMT3 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_FRSC_AMT4, 0), A.PRE_FRSC_AMT4)) AS PRE_FRSC_AMT4 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_FRSC_AMT5, 0), A.PRE_FRSC_AMT5)) AS PRE_FRSC_AMT5 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_FRSC_AMT6, 0), A.PRE_FRSC_AMT6)) AS PRE_FRSC_AMT6 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_DEF_FRSC_AMT1, 0), A.PRE_DEF_FRSC_AMT1)) AS PRE_DEF_FRSC_AMT1 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_DEF_FRSC_AMT2, 0), A.PRE_DEF_FRSC_AMT2)) AS PRE_DEF_FRSC_AMT2 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_DEF_FRSC_AMT3, 0), A.PRE_DEF_FRSC_AMT3)) AS PRE_DEF_FRSC_AMT3 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_DEF_FRSC_AMT4, 0), A.PRE_DEF_FRSC_AMT4)) AS PRE_DEF_FRSC_AMT4 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_DEF_FRSC_AMT5, 0), A.PRE_DEF_FRSC_AMT5)) AS PRE_DEF_FRSC_AMT5 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_DEF_FRSC_AMT6, 0), A.PRE_DEF_FRSC_AMT6)) AS PRE_DEF_FRSC_AMT6 FROM (SELECT A.FIS_YEAR AS FIS_YEAR , A.BGT_DGR AS BGT_DGR , A.TE_BGT_COMPO_ID AS TE_BGT_COMPO_ID , A.UP_TE_BGT_COMPO_ID AS UP_TE_BGT_COMPO_ID , A.DEPT_CD AS DEPT_CD , A.DBIZ_CD AS DBIZ_CD , A.TE_MNG_MOK_CD AS TE_MNG_MOK_CD , A.COMPO_LEVEL AS COMPO_LEVEL , A.COMP_GROUND AS COMP_GROUND , A.SORT_SEQ AS SORT_SEQ , A.TE_BGT_COMPO_SEQ , B.OFFICE_CD AS OFFICE_CD , E.REPORT_CD AS REPORT_CD , E.REPORT_DETL_CD AS REPORT_DETL_CD , E.REFLECT_FG AS REFLECT_FG , E.DEMAND_CONT AS DEMAND_CONT , E.EXAM_CONT AS EXAM_CONT , E.MAYOR_REPORT_YN AS MAYOR_REPORT_YN , (SELECT NVL(SUM(DECODE(CC.STAND_FRSC_CD, '160', BB.ADJ_DEF_FRSC_AMT, 0)), 0) FROM TB_DGRCOMPOFRSC BB, TB_YEARFRSC CC WHERE 1 = 1 AND CC.FIS_YEAR = BB.FIS_YEAR AND CC.FRSC_FG_CD = BB.FRSC_FG_CD AND BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS FRSC_AMT1 , (SELECT NVL(SUM(DECODE(CC.STAND_FRSC_CD, '110', BB.ADJ_DEF_FRSC_AMT, '120', BB.ADJ_DEF_FRSC_AMT, '130', BB.ADJ_DEF_FRSC_AMT, 0)), 0) FROM TB_DGRCOMPOFRSC BB, TB_YEARFRSC CC WHERE 1 = 1 AND CC.FIS_YEAR = BB.FIS_YEAR AND CC.FRSC_FG_CD = BB.FRSC_FG_CD AND BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS FRSC_AMT2 , (SELECT NVL(SUM(DECODE(CC.STAND_FRSC_CD, '140', BB.ADJ_DEF_FRSC_AMT, '150', BB.ADJ_DEF_FRSC_AMT, 0)), 0) FROM TB_DGRCOMPOFRSC BB, TB_YEARFRSC CC WHERE 1 = 1 AND CC.FIS_YEAR = BB.FIS_YEAR AND CC.FRSC_FG_CD = BB.FRSC_FG_CD AND BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS FRSC_AMT3 , (SELECT NVL(SUM(DECODE(CC.STAND_FRSC_CD, '180', BB.ADJ_DEF_FRSC_AMT, 0)), 0) FROM TB_DGRCOMPOFRSC BB, TB_YEARFRSC CC WHERE 1 = 1 AND CC.FIS_YEAR = BB.FIS_YEAR AND CC.FRSC_FG_CD = BB.FRSC_FG_CD AND BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS FRSC_AMT4 , (SELECT NVL(SUM(DECODE(CC.STAND_FRSC_CD, '190', BB.ADJ_DEF_FRSC_AMT, 0)), 0) FROM TB_DGRCOMPOFRSC BB, TB_YEARFRSC CC WHERE 1 = 1 AND CC.FIS_YEAR = BB.FIS_YEAR AND CC.FRSC_FG_CD = BB.FRSC_FG_CD AND BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS FRSC_AMT5 , (SELECT NVL(SUM(DECODE(CC.STAND_FRSC_CD, '170', BB.ADJ_DEF_FRSC_AMT, '200', BB.ADJ_DEF_FRSC_AMT, '210', BB.ADJ_DEF_FRSC_AMT, 0)), 0) FROM TB_DGRCOMPOFRSC BB, TB_YEARFRSC CC WHERE 1 = 1 AND CC.FIS_YEAR = BB.FIS_YEAR AND CC.FRSC_FG_CD = BB.FRSC_FG_CD AND BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS FRSC_AMT6 , (SELECT NVL(SUM(DECODE(CC.STAND_FRSC_CD, '160', BB.DMN_DEF_FRSC_AMT, 0)), 0) FROM TB_DGRCOMPOFRSC BB, TB_YEARFRSC CC WHERE 1 = 1 AND CC.FIS_YEAR = BB.FIS_YEAR AND CC.FRSC_FG_CD = BB.FRSC_FG_CD AND BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS DMN_FRSC_AMT1 , (SELECT NVL(SUM(DECODE(CC.STAND_FRSC_CD, '110', BB.DMN_DEF_FRSC_AMT, '120', BB.DMN_DEF_F