) A , (SELECT ROWNUM AS CT FROM TB_COMMCD WHERE ROWNUM BETWEEN 1 AND 2) H WHERE 1 = 1 GROUP BY DECODE(H.CT, 1, A.FIS_YEAR || '_' || TO_CHAR(A.BGT_DGR, '000') || '_' || A.REPORT_DETL_CD || '_' || A.OFFICE_CD || '_' '00000000000' , 2, A.FIS_YEAR || '_' || TO_CHAR(A.BGT_DGR, '000') || '_' || A.REPORT_DETL_CD || '_' || A.OFFICE_CD || '_' || A.TE_BGT_COMPO_ID) ) T ) A ) T WHERE 1 = 1 ORDER BY T.FIS_YEAR , NVL(T.BGT_DGR, 0) , NVL(T.OFFICE_RANK, 0) , NVL(T.OFFICE_CD, '0000') , NVL(T.DEPT_RANK, 0) , NVL(T.DEPT_CD, '0000000') , NVL(T.PBIZ_RANK, 0) , NVL(T.PBIZ_CD, '0000000000000000') , NVL(T.UBIZ_RANK, 0) , NVL(T.UBIZ_CD, '0000000000000000') , NVL(T.DBIZ_RANK, 0) , NVL(T.DBIZ_CD, '0000000000000000') , NVL(T.TE_MNG_MOK_CD, '00000') , NVL(T.SORT_SEQ, 0)
